urlset:
{%- for sitemap_entry in entries %}
{%- set hide_from_home = sitemap_entry.extra.hide_from_home | default(value=false) %}
{%- if not hide_from_home %}

    {{ sitemap_entry.permalink | escape_xml | safe }}
    {%- if sitemap_entry.updated %}
    {{ sitemap_entry.updated }}
    {%- endif %}

{%- endif %}
{%- endfor %}
